const root = $input.first().json || {};
const body = (root.body && typeof root.body === 'object') ? root.body : root;

if (String(body.action || '') === '__orbital_connectivity_probe__') {
  const now = new Date();
  const end = new Date(now.getTime() + 3600000);
  return [{ json: { calendar_op: 'list', time_min: now.toISOString(), time_max: end.toISOString() } }];
}

const rawOp = String(body.calendar_op || body.op || '').toLowerCase().trim();
let calendar_op = '';

if (rawOp === 'delete' || rawOp === 'remove') calendar_op = 'delete';
else if (rawOp === 'list' || rawOp === 'get_many' || rawOp === 'search') calendar_op = 'list';
else if (rawOp === 'create' || rawOp === 'add') calendar_op = 'create';
else if (rawOp === 'update' || rawOp === 'edit' || rawOp === 'patch') calendar_op = 'update';

if (!calendar_op && body.event_id && body.starts_at_iso) calendar_op = 'update';
if (!calendar_op && body.event_id && !body.starts_at_iso) calendar_op = 'delete';
if (!calendar_op && (body.time_min || body.time_max)) calendar_op = 'list';
if (!calendar_op && body.starts_at_iso) calendar_op = 'create';
if (!calendar_op) {
  throw new Error('Payload incompleto: use calendar_op (create|update|delete|list) ou starts_at_iso / event_id / time_min.');
}

if (calendar_op === 'create') {
  const title = String(body.title || 'Lembrete').trim();
  const startsIso = String(body.starts_at_iso || '').trim();
  if (!startsIso) throw new Error('starts_at_iso e obrigatorio para create');
  const starts = new Date(startsIso);
  if (Number.isNaN(starts.getTime())) throw new Error('starts_at_iso invalido');
  const ends = body.ends_at_iso
    ? new Date(String(body.ends_at_iso))
    : new Date(starts.getTime() + 30 * 60 * 1000);
  if (Number.isNaN(ends.getTime())) throw new Error('ends_at_iso invalido');
  const notes = String(body.notes || 'Criado pela ATHENAS').trim();
  return [{
    json: {
      calendar_op: 'create',
      title,
      summary: title,
      notes,
      starts_at_iso: starts.toISOString(),
      ends_at_iso: ends.toISOString(),
    },
  }];
}

if (calendar_op === 'update') {
  const eventId = String(body.event_id || body.id || '').trim();
  if (!eventId) throw new Error('event_id e obrigatorio para update');
  const out = { calendar_op: 'update', event_id: eventId };
  if (body.title) out.title = String(body.title).trim();
  if (body.starts_at_iso) {
    const s = new Date(String(body.starts_at_iso));
    if (Number.isNaN(s.getTime())) throw new Error('starts_at_iso invalido');
    out.starts_at_iso = s.toISOString();
  }
  if (body.ends_at_iso) {
    const e = new Date(String(body.ends_at_iso));
    if (Number.isNaN(e.getTime())) throw new Error('ends_at_iso invalido');
    out.ends_at_iso = e.toISOString();
  }
  if (body.notes) out.notes = String(body.notes).trim();
  return [{ json: out }];
}

if (calendar_op === 'delete') {
  const eventId = String(body.event_id || body.id || '').trim();
  if (!eventId) throw new Error('event_id e obrigatorio para delete');
  return [{ json: { calendar_op: 'delete', event_id: eventId } }];
}

const timeMinRaw = body.time_min ? String(body.time_min) : '';
const timeMaxRaw = body.time_max ? String(body.time_max) : '';
const timeMin = timeMinRaw ? new Date(timeMinRaw) : new Date();
const timeMax = timeMaxRaw
  ? new Date(timeMaxRaw)
  : new Date(Date.now() + 7 * 24 * 60 * 60 * 1000);
if (Number.isNaN(timeMin.getTime()) || Number.isNaN(timeMax.getTime())) {
  throw new Error('time_min/time_max invalido');
}
return [{
  json: {
    calendar_op: 'list',
    time_min: timeMin.toISOString(),
    time_max: timeMax.toISOString(),
  },
}];

const items = $input.all().map((i) => {
  const j = i.json || {};
  // Detect n8n error output
  if (j.error || j.errorMessage) {
    return { error: true, message: j.errorMessage || j.message || j.error || 'Unknown GCal error' };
  }
  return {
    id: j.id || null,
    summary: j.summary || null,
    start: j.start?.dateTime || j.start?.date || null,
    end: j.end?.dateTime || j.end?.date || null,
    htmlLink: j.htmlLink || null,
  };
});
const hasError = items.some(i => i.error);
if (hasError) {
  const errMsg = items.find(i => i.error)?.message || 'Erro ao listar eventos';
  return [{ json: { ok: false, calendar_op: 'list', message: errMsg, events: [], count: 0 } }];
}
return [{ json: { ok: true, calendar_op: 'list', events: items, count: items.length } }];

const j = $input.first().json || {};
if (j.error || j.errorMessage) {
  return [{ json: {
    ok: false,
    message: j.errorMessage || j.message || j.error || 'Erro ao criar evento',
    data: null
  }}];
}
return [{ json: {
  ok: true,
  message: 'Reminder created',
  data: {
    id: j.id || null,
    title: $('Parse Calendar').first().json.title,
    starts_at_iso: $('Parse Calendar').first().json.starts_at_iso,
    ends_at_iso: $('Parse Calendar').first().json.ends_at_iso,
    htmlLink: j.htmlLink || null
  }
}}];

const j = $input.first().json || {};
if (j.error || j.errorMessage) {
  return [{ json: {
    ok: false,
    message: j.errorMessage || j.message || j.error || 'Erro ao atualizar evento',
    data: null
  }}];
}
return [{ json: {
  ok: true,
  message: 'Event updated',
  data: {
    id: j.id || $('Parse Calendar').first().json.event_id || null,
    title: j.summary || $('Parse Calendar').first().json.title || null,
    starts_at_iso: j.start?.dateTime || $('Parse Calendar').first().json.starts_at_iso || null,
    ends_at_iso: j.end?.dateTime || $('Parse Calendar').first().json.ends_at_iso || null,
    htmlLink: j.htmlLink || null
  }
}}];

const j = $input.first().json || {};
if (j.error || j.errorMessage) {
  return [{ json: {
    ok: false,
    message: j.errorMessage || j.message || j.error || 'Erro ao apagar evento',
    data: null
  }}];
}
return [{ json: {
  ok: true,
  message: 'Event deleted',
  data: { event_id: $('Parse Calendar').first().json.event_id }
}}];
